   156		certificate, err := x509.ParseCertificate(certificateBlock.Bytes)
   157		if err != nil {
   158			return nil, fmt.Errorf("failed to parse certificate: %w", err)
   159		}
   160	
   161		hosts := []string{certificate.Subject.CommonName}
   162	
   163		for _, name := range certificate.DNSNames {
   164			hosts = append(hosts, name)
   165		}
   166	
   167		for _, ip := range certificate.IPAddresses {
   168			hosts = append(hosts, ip.String())
   169		}
   170	
   171		return hosts, nil
   172	}
