   281	// getReadyListeners returns a map containing the list of upstreams for each listener that is ready
   282	func getReadyListeners(cfgSnap *proxycfg.ConfigSnapshot) map[string]readyListener {
   283		ready := map[string]readyListener{}
   284		for _, l := range cfgSnap.APIGateway.Listeners {
   285			// Only include upstreams for listeners that are ready
   286			if !cfgSnap.APIGateway.GatewayConfig.ListenerIsReady(l.Name) {
   287				continue
   288			}
   289	
   290			// For each route bound to the listener
   291			boundListener := cfgSnap.APIGateway.BoundListeners[l.Name]
   292			for _, routeRef := range boundListener.Routes {
   293				// Get all upstreams for the route
   294				routeUpstreams, ok := cfgSnap.APIGateway.Upstreams[routeRef]
   295				if !ok {
   296					continue
   297				}
   298	
   299				// Filter to upstreams that attach to this specific listener since
   300				// a route can bind to + have upstreams for multiple listeners
   301				listenerKey := proxycfg.APIGatewayListenerKeyFromListener(l)
   302				routeUpstreamsForListener, ok := routeUpstreams[listenerKey]
   303				if !ok {
   304					continue
   305				}
   306	
   307				for _, upstream := range routeUpstreamsForListener {
   308					// Insert or update readyListener for the listener to include this upstream
   309					r, ok := ready[l.Name]
   310					if !ok {
   311						r = readyListener{
   312							listenerKey:      listenerKey,
   313							listenerCfg:      l,
   314							routeReferences:  map[structs.ResourceReference]struct{}{},
   315							boundListenerCfg: boundListener,
   316						}
   317					}
   318					r.routeReferences[routeRef] = struct{}{}
   319					r.upstreams = append(r.upstreams, upstream)
   320					ready[l.Name] = r
   321				}
   322			}
   323		}
   324		return ready
   325	}
