			name:           "no certificates",
			fileSystemCerts: nil,
			expectSecrets:  0,
			expectNames:    nil,
		},
		{
			name: "single file system certificate",
			fileSystemCerts: []structs.FileSystemCertificateConfigEntry{
				{
					Kind:        structs.FileSystemCertificate,
					Name:        "cert-one",
					Certificate: "/path/to/cert.pem",
					PrivateKey:  "/path/to/key.pem",
				},
			},
			expectSecrets: 1,
			expectNames:   []string{"cert-one"},
		},
		{
			name: "multiple file system certificates",
			fileSystemCerts: []structs.FileSystemCertificateConfigEntry{
				{
					Kind:        structs.FileSystemCertificate,
					Name:        "cert-one",
					Certificate: "/path/to/cert1.pem",
					PrivateKey:  "/path/to/key1.pem",
				},
				{
					Kind:        structs.FileSystemCertificate,
					Name:        "cert-two",
					Certificate: "/path/to/cert2.pem",
					PrivateKey:  "/path/to/key2.pem",
				},
			},
			expectSecrets: 2,
			expectNames:   []string{"cert-one", "cert-two"},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			snap := &proxycfg.ConfigSnapshot{
				Kind: structs.ServiceKindAPIGateway,
				APIGateway: proxycfg.APIGatewaySnapshot{
					FileSystemCertificates: watch.NewMap[structs.ResourceReference, *structs.FileSystemCertificateConfigEntry](),
				},
			}

			for _, cert := range tt.fileSystemCerts {
				cert := cert
				ref := structs.ResourceReference{
					Kind: structs.FileSystemCertificate,
					Name: cert.Name,
				}
				snap.APIGateway.FileSystemCertificates.InitWatch(ref, nil)
				snap.APIGateway.FileSystemCertificates.Set(ref, &cert)
			}

			s := &ResourceGenerator{}
			resources, err := s.secretsFromSnapshot(snap)
			require.NoError(t, err)
			require.Len(t, resources, tt.expectSecrets)

			if tt.expectNames != nil {
				foundNames := make(map[string]bool)
				for _, r := range resources {
					secret := r.(*envoy_tls_v3.Secret)
					foundNames[secret.Name] = true

					// Verify the secret uses filename data source
					tlsCert := secret.GetTlsCertificate()
					require.NotNil(t, tlsCert)

					certChain := tlsCert.GetCertificateChain()
					require.NotNil(t, certChain)
					_, ok := certChain.Specifier.(*envoy_core_v3.DataSource_Filename)
					require.True(t, ok, "certificate chain should use filename data source")

					privKey := tlsCert.GetPrivateKey()
					require.NotNil(t, privKey)
					_, ok = privKey.Specifier.(*envoy_core_v3.DataSource_Filename)
					require.True(t, ok, "private key should use filename data source")
				}

				for _, name := range tt.expectNames {
					require.True(t, foundNames[name], "expected secret with name %q", name)
				}
			}
		})
	}
}

func TestMakeEnvoySecretFromFileSystemCertificate(t *testing.T) {
	cert := &structs.FileSystemCertificateConfigEntry{
		Kind:        structs.FileSystemCertificate,
		Name:        "my-cert",
		Certificate: "/opt/consul/tls/api-gateway.crt",
		PrivateKey:  "/opt/consul/tls/api-gateway.key",
	}

	secret := makeEnvoySecretFromFileSystemCertificate(cert)

	require.Equal(t, "my-cert", secret.Name)

	tlsCert := secret.GetTlsCertificate()
	require.NotNil(t, tlsCert)

	certChain := tlsCert.GetCertificateChain()
	require.NotNil(t, certChain)
	require.Equal(t, "/opt/consul/tls/api-gateway.crt", certChain.GetFilename())

	privKey := tlsCert.GetPrivateKey()
	require.NotNil(t, privKey)
	require.Equal(t, "/opt/consul/tls/api-gateway.key", privKey.GetFilename())
}

