	envoy_core_v3 "github.com/envoyproxy/go-control-plane/envoy/config/core/v3"
	envoy_tls_v3 "github.com/envoyproxy/go-control-plane/envoy/extensions/transport_sockets/tls/v3"
	"github.com/stretchr/testify/require"

	"github.com/hashicorp/consul/agent/structs"
)

func TestMakeEnvoySecretFromFileSystemCertificate(t *testing.T) {
	tests := []struct {
		name     string
		cert     *structs.FileSystemCertificateConfigEntry
		wantName string
		wantCert string
		wantKey  string
	}{
		{
			name: "basic certificate",
			cert: &structs.FileSystemCertificateConfigEntry{
				Kind:        structs.FileSystemCertificate,
				Name:        "my-cert",
				Certificate: "/opt/consul/tls/api-gateway.crt",
				PrivateKey:  "/opt/consul/tls/api-gateway.key",
			},
			wantName: "my-cert",
			wantCert: "/opt/consul/tls/api-gateway.crt",
			wantKey:  "/opt/consul/tls/api-gateway.key",
		},
		{
			name: "empty paths",
			cert: &structs.FileSystemCertificateConfigEntry{
				Kind:        structs.FileSystemCertificate,
				Name:        "empty-cert",
				Certificate: "",
				PrivateKey:  "",
			},
			wantName: "empty-cert",
			wantCert: "",
			wantKey:  "",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			secret := makeEnvoySecretFromFileSystemCertificate(tt.cert)

			require.Equal(t, tt.wantName, secret.Name)

			tlsCert := secret.GetTlsCertificate()
			require.NotNil(t, tlsCert)

			certChain := tlsCert.GetCertificateChain()
			require.NotNil(t, certChain)
			filename, ok := certChain.Specifier.(*envoy_core_v3.DataSource_Filename)
			require.True(t, ok, "certificate chain should use filename data source")
			require.Equal(t, tt.wantCert, filename.Filename)

			privKey := tlsCert.GetPrivateKey()
			require.NotNil(t, privKey)
			keyFilename, ok := privKey.Specifier.(*envoy_core_v3.DataSource_Filename)
			require.True(t, ok, "private key should use filename data source")
			require.Equal(t, tt.wantKey, keyFilename.Filename)
		})
	}
}

func TestSecretsFromSnapshot_InvalidKind(t *testing.T) {
	s := &ResourceGenerator{}
	_, err := s.secretsFromSnapshot(nil)
	require.Error(t, err)
	require.Contains(t, err.Error(), "nil config given")
}

func TestSecretsFromSnapshot_NonAPIGatewayReturnsEmpty(t *testing.T) {
	testCases := []struct {
		kind structs.ServiceKind
	}{
		{structs.ServiceKindConnectProxy},
		{structs.ServiceKindTerminatingGateway},
		{structs.ServiceKindMeshGateway},
		{structs.ServiceKindIngressGateway},
	}

	for _, tc := range testCases {
		t.Run(string(tc.kind), func(t *testing.T) {
			snap := &proxycfg.ConfigSnapshot{
				Kind: tc.kind,
			}
			s := &ResourceGenerator{}
			resources, err := s.secretsFromSnapshot(snap)
			require.NoError(t, err)
			require.Empty(t, resources)
		})
	}
}

func TestMakeEnvoySecretFromFileSystemCertificate_SecretStructure(t *testing.T) {
	cert := &structs.FileSystemCertificateConfigEntry{
		Kind:        structs.FileSystemCertificate,
		Name:        "test-cert",
		Certificate: "/path/to/cert.pem",
		PrivateKey:  "/path/to/key.pem",
	}

	secret := makeEnvoySecretFromFileSystemCertificate(cert)

	// Verify it's a proper envoy TLS secret
	require.IsType(t, &envoy_tls_v3.Secret{}, secret)

	// Verify the type is TlsCertificate (not validation context or other types)
	tlsCertType := secret.GetTlsCertificate()
	require.NotNil(t, tlsCertType, "secret should be of type TlsCertificate")
}
